const data = $input.first().json;
const raw = data.rawRequest || {};

// Candidate Info
const nameObj = raw['Name'] || {};
const firstName = typeof nameObj === 'object' ? (nameObj.first || '') : String(nameObj);
const lastName  = typeof nameObj === 'object' ? (nameObj.last  || '') : '';
const candidateName  = (firstName + ' ' + lastName).trim();
const candidateEmail = raw['Email'] || '';
const submissionDate = new Date().toISOString().split('T')[0];
const videoLink = raw['Short Intro Video link'] || 'Not provided';

// Strip HTML helper
function stripHtml(str) {
  if (typeof str !== 'string') return String(str || '');
  return str
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<b>(.*?)<\/b>/gi, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"').replace(/&nbsp;/g, ' ')
    .trim();
}

// Part 1 — Priority Ranking
const rankingKey = Object.keys(raw).find(k => k.includes('Prioritize the emails'));
const priorityRanking = rankingKey ? stripHtml(raw[rankingKey]) : 'Not provided';

// Part 1 — Action Matrix
const matrixKey = Object.keys(raw).find(k => k.includes('Identify what needs immediate action'));
const actionMatrix = matrixKey ? (raw[matrixKey] || {}) : {};
const emailLabels = [
  'Email 1 — URGENT: Client unhappy about missed deadline',
  'Email 2 — Podcast Invitation',
  'Email 3 — Team Internal: Project Delay',
  'Email 4 — Invoice Approval',
  'Email 5 — Calendar Conflict Tomorrow'
];
const immediateActions = [], canWait = [], toDelegate = [];
for (let i = 0; i < 5; i++) {
  const row = actionMatrix[i.toString()];
  if (!row) continue;
  let category = null;
  if (Array.isArray(row)) { category = row[0]; }
  else if (typeof row === 'object') { const vals = Object.values(row); if (vals.length) category = vals[0]; }
  if (category === 'Needs Immediate Action') immediateActions.push('• ' + emailLabels[i]);
  else if (category === 'Can Wait')           canWait.push('• '           + emailLabels[i]);
  else if (category === 'Should be Delegated') toDelegate.push('• '      + emailLabels[i]);
}

// Part 1 — Draft Replies
const draft1Key = Object.keys(raw).find(k => k.includes('#1 highest priority'));
const draft2Key = Object.keys(raw).find(k => k.includes('#2 highest priority'));
const draftReply1 = draft1Key ? stripHtml(raw[draft1Key]) : 'Not provided';
const draftReply2 = draft2Key ? stripHtml(raw[draft2Key]) : 'Not provided';

// Part 2 — Calendar
const scheduleKey  = Object.keys(raw).find(k => k.toLowerCase().includes('reorganize the schedule'));
const reasoningKey = Object.keys(raw).find(k => k.toLowerCase().includes('explain your reasoning'));
const revisedSchedule   = scheduleKey  ? stripHtml(raw[scheduleKey])  : 'Not provided';
const calendarReasoning = reasoningKey ? stripHtml(raw[reasoningKey]) : 'Not provided';

// Part 3 — Project Breakdown
const projectKey  = Object.keys(raw).find(k => k.toLowerCase().includes('plan to execute') || k.toLowerCase().includes('simple plan'));
const projectPlan = projectKey ? stripHtml(raw[projectKey]) : 'Not provided';

// Part 4 — Bilingual
const engKey = Object.keys(raw).find(k => k.toLowerCase().includes('english'));
const spaKey = Object.keys(raw).find(k => k.toLowerCase().includes('spanish'));
const bilingualEnglish = engKey ? stripHtml(raw[engKey]) : 'Not provided';
const bilingualSpanish = spaKey ? stripHtml(raw[spaKey]) : 'Not provided';

const formattedSubmission = [
  'CANDIDATE SUBMISSION', '---',
  'Name: ' + candidateName,
  'Email: ' + candidateEmail,
  'Date Submitted: ' + submissionDate, '',
  'PART 1 — INBOX PRIORITIZATION', '',
  'Priority Ranking (1 = most urgent):', priorityRanking, '',
  'Immediate Action Items:', (immediateActions.length ? immediateActions.join('\n') : '• Not specified'), '',
  'Can Wait:', (canWait.length ? canWait.join('\n') : '• Not specified'), '',
  'Delegate:', (toDelegate.length ? toDelegate.join('\n') : '• Not specified'), '',
  'Draft Reply — Email 1 (Highest Priority):', draftReply1, '',
  'Draft Reply — Email 2 (Second Priority):', draftReply2, '',
  'PART 2 — CALENDAR DECISION', '',
  'Revised Schedule:', revisedSchedule, '',
  'Reasoning:', calendarReasoning, '',
  'PART 3 — PROJECT BREAKDOWN', '',
  'Objective: Launch a 2-week employee referral program', '',
  'Plan / Key Steps:', projectPlan, '',
  'PART 4 — BILINGUAL RESPONSE', '',
  'English:', bilingualEnglish, '',
  'Spanish:', bilingualSpanish
].join('\n');

return [{ json: { candidateName, candidateEmail, submissionDate, videoLink, formattedSubmission } }];

const agentOutput = $input.first().json.output || $input.first().json.text || $input.first().json.message || '';
const prevData = $('Format Submission').first().json;

// Strip bold markers before parsing
const clean = agentOutput.replace(/\*\*/g, '');

function extractScore(text, label) {
  const esc = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = text.match(new RegExp(esc + ':\\s*(\\d+)\\s*/\\s*5', 'i'));
  return m ? parseInt(m[1]) : null;
}

function extractReasoning(text, startLabel, endLabel) {
  const esc = s => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const startReg = new RegExp(esc(startLabel) + '[^\\n]*\\nReasoning:\\s*', 'i');
  const startM = text.match(startReg);
  if (!startM) return '';
  const after = text.slice(startM.index + startM[0].length);
  if (endLabel) {
    const endM = after.match(new RegExp(esc(endLabel), 'i'));
    return endM ? after.slice(0, endM.index).trim() : after.trim();
  }
  return after.trim();
}

const prioritizationScore = extractScore(clean, 'Prioritization');
const communicationScore  = extractScore(clean, 'Communication');
const decisionMakingScore = extractScore(clean, 'Decision-Making');
const structureScore      = extractScore(clean, 'Structure & Thinking');

const bilingualRaw = clean.match(/Bilingual Communication:\s*(?:(\d+)\s*\/\s*5|(Not scored))/i);
const bilingualScore = bilingualRaw ? (bilingualRaw[1] ? parseInt(bilingualRaw[1]) : 'Not scored') : 'Not scored';

const prioritizationReasoning = extractReasoning(clean, 'Prioritization:', 'Communication:');
const communicationReasoning  = extractReasoning(clean, 'Communication:', 'Decision-Making:');
const decisionReasoning       = extractReasoning(clean, 'Decision-Making:', 'Structure & Thinking:');
const structureReasoning      = extractReasoning(clean, 'Structure & Thinking:', 'Bilingual Communication:');
const bilingualReasoning      = extractReasoning(clean, 'Bilingual Communication:', 'Strengths:');

const strengthsM      = clean.match(/Strengths:\s*([\s\S]*?)(?=Red Flags:|$)/i);
const redFlagsM       = clean.match(/Red Flags:\s*([\s\S]*?)(?=Final Recommendation:|$)/i);
const recommendationM = clean.match(/Final Recommendation:\s*(PASS|BORDERLINE|FAIL)/i);
const explanationM    = clean.match(/Overall Explanation:\s*([\s\S]*?)$/i);

const strengths           = strengthsM      ? strengthsM[1].trim()           : '';
const redFlags            = redFlagsM       ? redFlagsM[1].trim()            : '';
const finalRecommendation = recommendationM ? recommendationM[1].toUpperCase() : 'BORDERLINE';
const overallExplanation  = explanationM    ? explanationM[1].trim()         : '';

return [{ json: {
  candidateName:            prevData.candidateName,
  candidateEmail:           prevData.candidateEmail,
  submissionDate:           prevData.submissionDate,
  videoLink:                prevData.videoLink,
  prioritizationScore, communicationScore, decisionMakingScore, structureScore, bilingualScore,
  prioritizationReasoning, communicationReasoning, decisionReasoning, structureReasoning, bilingualReasoning,
  strengths, redFlags, finalRecommendation, overallExplanation,
  fullEvaluation: agentOutput
}}];

const item = $input.first().json;

const raw = item.formattedSubmission;

const priorities = [];
const priorityRegex = /(\d):\s*<b>(Email \d)<\/b><br><b>Subject:<\/b>\s*(.*?)<br><b>Message:<\/b>\s*"([^"]+)"/g;
let m;
while ((m = priorityRegex.exec(raw)) !== null) {
  priorities.push({
    rank: parseInt(m[1]),
    email: m[2],
    subject: m[3].trim(),
    message: m[4].trim()
  });
}

const actionMap = {};

const immediateBlock = raw.match(/Immediate Action Items:\n([\s\S]*?)(?=\nCan Wait:|$)/)?.[1] || '';
immediateBlock.match(/•\s*(.+)/g)?.forEach(l => {
  const label = l.replace('•', '').trim();
  actionMap[label] = 'Immediate action';
});

const waitBlock = raw.match(/Can Wait:\n([\s\S]*?)(?=\nDelegate:|$)/)?.[1] || '';
waitBlock.match(/•\s*(.+)/g)?.forEach(l => {
  const label = l.replace('•', '').trim();
  actionMap[label] = 'Can wait';
});

const delegateBlock = raw.match(/Delegate:\n([\s\S]*?)(?=\nDraft Reply|$)/)?.[1] || '';
delegateBlock.match(/•\s*(.+)/g)?.forEach(l => {
  const label = l.replace('•', '').trim();
  actionMap[label] = 'Delegate';
});

const draftReply1 = raw.match(/Draft Reply — Email 1[^:]*:\n([\s\S]*?)(?=\nDraft Reply — Email 2|$)/)?.[1]?.trim() || '';
const draftReply2 = raw.match(/Draft Reply — Email 2[^:]*:\n([\s\S]*?)(?=\nPART 2|$)/)?.[1]?.trim() || '';

const scheduleBlock = raw.match(/Revised Schedule:\n([\s\S]*?)(?=\nReasoning:|$)/)?.[1] || '';
const scheduleItems = scheduleBlock.trim().split(/\r?\n\r?\n/).map(s => s.trim()).filter(Boolean);

const reasoning = raw.match(/Reasoning:\n([\s\S]*?)(?=\nPART 3|$)/)?.[1]?.trim() || '';

const projectPlan = raw.match(/Plan \/ Key Steps:\n([\s\S]*?)(?=\nPART 4|$)/)?.[1]?.trim() || '';

const englishResponse = raw.match(/English:\n([\s\S]*?)(?=\nSpanish:|$)/)?.[1]?.trim() || '';
const spanishResponse = raw.match(/Spanish:\n([\s\S]*?)$/)?.[1]?.trim() || '';

return [{
  json: {
    candidateName: item.candidateName,
    candidateEmail: item.candidateEmail,
    submissionDate: item.submissionDate,
    videoLink: item.videoLink,
    part1: {
      priorityRanking: priorities,
      actionClassification: actionMap,
      draftReply1,
      draftReply2
    },
    part2: {
      schedule: scheduleItems,
      reasoning
    },
    part3: {
      projectPlan
    },
    part4: {
      englishResponse,
      spanishResponse
    }
  }
}];

const agentOutput = $input.first().json.output || $input.first().json.text || $input.first().json.message || '';
const prevData = $('Format Submission').first().json;

function extractScore(text, label) {
  const esc = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = text.match(new RegExp(esc + ':\\s*(\\d+)\\s*/\\s*5', 'i'));
  return m ? parseInt(m[1]) : null;
}

function extractReasoning(text, startLabel, endLabel) {
  const esc = s => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const startReg = new RegExp(esc(startLabel) + '[^\\n]*\\nReasoning:\\s*', 'i');
  const startM = text.match(startReg);
  if (!startM) return '';
  const after = text.slice(startM.index + startM[0].length);
  if (endLabel) {
    const endM = after.match(new RegExp(esc(endLabel), 'i'));
    return endM ? after.slice(0, endM.index).trim() : after.trim();
  }
  return after.trim();
}

const prioritizationScore  = extractScore(agentOutput, 'Prioritization');
const communicationScore   = extractScore(agentOutput, 'Communication');
const decisionMakingScore  = extractScore(agentOutput, 'Decision-Making');
const structureScore       = extractScore(agentOutput, 'Structure & Thinking');
const bilingualRaw = agentOutput.match(/Bilingual Communication:\s*(?:(\d+)\s*\/\s*5|(Not scored))/i);
const bilingualScore = bilingualRaw ? (bilingualRaw[1] ? parseInt(bilingualRaw[1]) : 'Not scored') : 'Not scored';

const prioritizationReasoning = extractReasoning(agentOutput, 'Prioritization:', 'Communication:');
const communicationReasoning  = extractReasoning(agentOutput, 'Communication:', 'Decision-Making:');
const decisionReasoning       = extractReasoning(agentOutput, 'Decision-Making:', 'Structure & Thinking:');
const structureReasoning      = extractReasoning(agentOutput, 'Structure & Thinking:', 'Bilingual Communication:');
const bilingualReasoning      = extractReasoning(agentOutput, 'Bilingual Communication:', 'Strengths:');

const strengthsM       = agentOutput.match(/Strengths:\s*([\s\S]*?)(?=Red Flags:|$)/i);
const redFlagsM        = agentOutput.match(/Red Flags:\s*([\s\S]*?)(?=Final Recommendation:|$)/i);
const recommendationM  = agentOutput.match(/Final Recommendation:\s*(PASS|BORDERLINE|FAIL)/i);
const explanationM     = agentOutput.match(/Overall Explanation:\s*([\s\S]*?)$/i);

const strengths            = strengthsM      ? strengthsM[1].trim()      : '';
const redFlags             = redFlagsM       ? redFlagsM[1].trim()       : '';
const finalRecommendation  = recommendationM ? recommendationM[1].toUpperCase() : 'BORDERLINE';
const overallExplanation   = explanationM    ? explanationM[1].trim()    : '';

return [{ json: {
  candidateName:           prevData.candidateName,
  candidateEmail:          prevData.candidateEmail,
  submissionDate:          prevData.submissionDate,
  videoLink:               prevData.videoLink,
  prioritizationScore, communicationScore, decisionMakingScore, structureScore, bilingualScore,
  prioritizationReasoning, communicationReasoning, decisionReasoning, structureReasoning, bilingualReasoning,
  strengths, redFlags, finalRecommendation, overallExplanation,
  fullEvaluation: agentOutput
}}];
